/**
 * Auth routes — 9 endpoints for email code + OAuth + session management
 */
import { Hono } from 'hono'
import type { Env } from '../index'
import { signAccessToken, verifyAccessToken, generateRefreshTokenId } from '../services/jwt'
import { sendVerificationEmail, generateCode } from '../services/email'
import {
  googleAuthUrl, googleExchangeCode, googleUserInfo,
  microsoftAuthUrl, microsoftExchangeCode, microsoftUserInfo,
} from '../services/oauth'
import type { OAuthUserInfo } from '../services/oauth'
import { authMiddleware } from '../middleware/auth'
import { verifyTurnstile } from '../services/turnstile'

type AuthEnv = { Bindings: Env; Variables: { userId: string; email: string } }

const FRONTEND_URL = 'https://clock.cosmelon.app'
const REFRESH_TOKEN_TTL = 30 * 24 * 60 * 60 // 30 days in seconds

export const authRoutes = new Hono<AuthEnv>()

// ─── Helpers ───

async function findOrCreateUser(
  db: D1Database, email: string, provider: string, name?: string, avatar?: string,
): Promise<{ id: string; email: string; display_name: string | null; avatar_url: string | null }> {
  const existing = await db.prepare('SELECT id, email, display_name, avatar_url FROM users WHERE email = ?').bind(email).first<{
    id: string; email: string; display_name: string | null; avatar_url: string | null
  }>()
  if (existing) return existing

  const id = crypto.randomUUID()
  await db.prepare(
    'INSERT INTO users (id, email, display_name, avatar_url, auth_provider) VALUES (?, ?, ?, ?, ?)',
  ).bind(id, email, name || null, avatar || null, provider).run()
  return { id, email, display_name: name || null, avatar_url: avatar || null }
}

async function issueTokens(
  env: Env, userId: string, email: string,
): Promise<{ accessToken: string; refreshTokenId: string }> {
  const accessToken = await signAccessToken(env.JWT_SECRET, userId, email)
  const refreshTokenId = generateRefreshTokenId()
  await env.SESSION_KV.put(`refresh:${refreshTokenId}`, userId, { expirationTtl: REFRESH_TOKEN_TTL })
  return { accessToken, refreshTokenId }
}

function setRefreshCookie(headers: Headers, refreshTokenId: string) {
  headers.set(
    'Set-Cookie',
    `refresh_token=${refreshTokenId}; HttpOnly; Secure; SameSite=None; Path=/auth; Max-Age=${REFRESH_TOKEN_TTL}`,
  )
}

function clearRefreshCookie(headers: Headers) {
  headers.set(
    'Set-Cookie',
    'refresh_token=; HttpOnly; Secure; SameSite=None; Path=/auth; Max-Age=0',
  )
}

function getRefreshTokenFromCookie(c: { req: { header: (name: string) => string | undefined } }): string | null {
  const cookie = c.req.header('Cookie') || ''
  const match = cookie.match(/refresh_token=([^;]+)/)
  return match ? match[1] : null
}

// ─── 1. POST /email/send-code ───

authRoutes.post('/email/send-code', async (c) => {
  const body = await c.req.json<{ email?: string; turnstileToken?: string }>()

  // Turnstile verification
  const turnstileToken = body.turnstileToken
  if (!turnstileToken) {
    return c.json({ error: 'Turnstile verification required' }, 403)
  }
  const ip = c.req.header('CF-Connecting-IP') || undefined
  const turnstileOk = await verifyTurnstile(c.env.TURNSTILE_SECRET, turnstileToken, ip)
  if (!turnstileOk) {
    return c.json({ error: 'Turnstile verification failed' }, 403)
  }

  // Global IP rate limit: max 5 requests per 60s
  const ipRateKey = `rate:ip:${ip || 'unknown'}`
  const ipAttempts = parseInt(await c.env.SESSION_KV.get(ipRateKey) || '0', 10)
  if (ipAttempts >= 5) {
    return c.json({ error: 'Too many requests from this IP' }, 429)
  }
  await c.env.SESSION_KV.put(ipRateKey, String(ipAttempts + 1), { expirationTtl: 60 })

  const email = body.email?.trim().toLowerCase()
  if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
    return c.json({ error: 'Invalid email' }, 400)
  }

  // Rate limit: 60s cooldown
  const rateKey = `rate:${email}`
  const existing = await c.env.SESSION_KV.get(rateKey)
  if (existing) {
    return c.json({ error: 'Please wait 60 seconds before requesting another code' }, 429)
  }

  const code = generateCode()
  await c.env.SESSION_KV.put(`code:${email}`, code, { expirationTtl: 900 })
  await c.env.SESSION_KV.put(rateKey, '1', { expirationTtl: 60 })

  const sent = await sendVerificationEmail(c.env.RESEND_API_KEY, email, code)
  if (!sent) {
    return c.json({ error: 'Failed to send email' }, 500)
  }

  return c.json({ ok: true })
})

// ─── 2. POST /email/verify ───

authRoutes.post('/email/verify', async (c) => {
  const body = await c.req.json<{ email?: string; code?: string }>()
  const email = body.email?.trim().toLowerCase()
  const code = body.code?.trim()
  if (!email || !code) return c.json({ error: 'Email and code required' }, 400)

  // Rate limit: max 5 verify attempts per email per 15 minutes
  const attemptKey = `verify_attempts:${email}`
  const attempts = parseInt(await c.env.SESSION_KV.get(attemptKey) || '0', 10)
  if (attempts >= 5) {
    return c.json({ error: 'Too many attempts. Please request a new code.' }, 429)
  }
  await c.env.SESSION_KV.put(attemptKey, String(attempts + 1), { expirationTtl: 900 })

  const stored = await c.env.SESSION_KV.get(`code:${email}`)
  if (!stored || stored !== code) {
    return c.json({ error: 'Invalid or expired code' }, 400)
  }

  // Delete used code and attempt counter
  await c.env.SESSION_KV.delete(`code:${email}`)
  await c.env.SESSION_KV.delete(attemptKey)

  const user = await findOrCreateUser(c.env.DB, email, 'email')
  const { accessToken, refreshTokenId } = await issueTokens(c.env, user.id, email)

  const res = c.json({
    accessToken,
    user: { id: user.id, email: user.email, displayName: user.display_name, avatarUrl: user.avatar_url },
  })
  setRefreshCookie(res.headers, refreshTokenId)
  return res
})

// ─── 3. GET /google/redirect ───

authRoutes.get('/google/redirect', async (c) => {
  const state = crypto.randomUUID()
  // Store state in KV with 10-minute TTL for CSRF validation
  await c.env.SESSION_KV.put(`oauth_state:${state}`, '1', { expirationTtl: 600 })
  const redirectUri = `${new URL(c.req.url).origin}/auth/google/callback`
  const url = googleAuthUrl(c.env.GOOGLE_CLIENT_ID, redirectUri, state)
  return c.redirect(url)
})

// ─── 4. GET /google/callback ───

authRoutes.get('/google/callback', async (c) => {
  const code = c.req.query('code')
  const state = c.req.query('state')
  if (!code) return c.json({ error: 'Missing code' }, 400)

  // Validate OAuth state to prevent CSRF
  if (!state) return c.json({ error: 'Missing state parameter' }, 400)
  const storedState = await c.env.SESSION_KV.get(`oauth_state:${state}`)
  if (!storedState) return c.json({ error: 'Invalid or expired state' }, 400)
  await c.env.SESSION_KV.delete(`oauth_state:${state}`)

  const redirectUri = `${new URL(c.req.url).origin}/auth/google/callback`
  const tokens = await googleExchangeCode(c.env.GOOGLE_CLIENT_ID, c.env.GOOGLE_CLIENT_SECRET, code, redirectUri)
  const info = await googleUserInfo(tokens.access_token)
  return handleOAuthCallback(c.env, info)
})

// ─── 5. GET /microsoft/redirect ───

authRoutes.get('/microsoft/redirect', async (c) => {
  const state = crypto.randomUUID()
  // Store state in KV with 10-minute TTL for CSRF validation
  await c.env.SESSION_KV.put(`oauth_state:${state}`, '1', { expirationTtl: 600 })
  const redirectUri = `${new URL(c.req.url).origin}/auth/microsoft/callback`
  const url = microsoftAuthUrl(c.env.MICROSOFT_CLIENT_ID, redirectUri, state)
  return c.redirect(url)
})

// ─── 6. GET /microsoft/callback ───

authRoutes.get('/microsoft/callback', async (c) => {
  const code = c.req.query('code')
  const state = c.req.query('state')
  if (!code) return c.json({ error: 'Missing code' }, 400)

  // Validate OAuth state to prevent CSRF
  if (!state) return c.json({ error: 'Missing state parameter' }, 400)
  const storedState = await c.env.SESSION_KV.get(`oauth_state:${state}`)
  if (!storedState) return c.json({ error: 'Invalid or expired state' }, 400)
  await c.env.SESSION_KV.delete(`oauth_state:${state}`)

  const redirectUri = `${new URL(c.req.url).origin}/auth/microsoft/callback`
  const tokens = await microsoftExchangeCode(c.env.MICROSOFT_CLIENT_ID, c.env.MICROSOFT_CLIENT_SECRET, code, redirectUri)
  const info = await microsoftUserInfo(tokens.access_token)
  return handleOAuthCallback(c.env, info)
})

async function handleOAuthCallback(env: Env, info: OAuthUserInfo): Promise<Response> {
  const user = await findOrCreateUser(env.DB, info.email, info.provider, info.name, info.picture)
  const { accessToken, refreshTokenId } = await issueTokens(env, user.id, info.email)

  const redirectUrl = `${FRONTEND_URL}/?auth=success#access_token=${accessToken}`
  const res = Response.redirect(redirectUrl, 302)
  // Response.redirect returns immutable headers, so we create a new response
  const mutableRes = new Response(res.body, {
    status: res.status,
    headers: new Headers(res.headers),
  })
  setRefreshCookie(mutableRes.headers, refreshTokenId)
  return mutableRes
}

// ─── 7. POST /refresh ───

authRoutes.post('/refresh', async (c) => {
  const refreshTokenId = getRefreshTokenFromCookie(c)
  if (!refreshTokenId) return c.json({ error: 'No refresh token' }, 401)

  const userId = await c.env.SESSION_KV.get(`refresh:${refreshTokenId}`)
  if (!userId) return c.json({ error: 'Invalid refresh token' }, 401)

  // Get user email
  const user = await c.env.DB.prepare('SELECT email FROM users WHERE id = ?').bind(userId).first<{ email: string }>()
  if (!user) return c.json({ error: 'User not found' }, 401)

  // Rotate refresh token
  await c.env.SESSION_KV.delete(`refresh:${refreshTokenId}`)
  const newAccessToken = await signAccessToken(c.env.JWT_SECRET, userId, user.email)
  const newRefreshId = generateRefreshTokenId()
  await c.env.SESSION_KV.put(`refresh:${newRefreshId}`, userId, { expirationTtl: REFRESH_TOKEN_TTL })

  const res = c.json({ accessToken: newAccessToken })
  setRefreshCookie(res.headers, newRefreshId)
  return res
})

// ─── 8. POST /logout ───

authRoutes.post('/logout', async (c) => {
  const refreshTokenId = getRefreshTokenFromCookie(c)
  if (refreshTokenId) {
    await c.env.SESSION_KV.delete(`refresh:${refreshTokenId}`)
  }
  const res = c.json({ ok: true })
  clearRefreshCookie(res.headers)
  return res
})

// ─── 9. GET /me ───

authRoutes.get('/me', authMiddleware, async (c) => {
  const userId = c.get('userId')
  const user = await c.env.DB.prepare(
    'SELECT id, email, display_name, avatar_url, created_at FROM users WHERE id = ?',
  ).bind(userId).first()
  if (!user) return c.json({ error: 'User not found' }, 404)
  return c.json({
    user: {
      id: user.id,
      email: user.email,
      displayName: user.display_name,
      avatarUrl: user.avatar_url,
      createdAt: user.created_at,
    },
  })
})

// ─── 10. PUT /profile — 修改昵称 ───

authRoutes.put('/profile', authMiddleware, async (c) => {
  const userId = c.get('userId')
  const body = await c.req.json<{ displayName?: string }>()
  const displayName = body.displayName?.trim()
  if (!displayName || displayName.length === 0 || displayName.length > 50) {
    return c.json({ error: 'Display name must be 1-50 characters' }, 400)
  }

  await c.env.DB.prepare(
    'UPDATE users SET display_name = ?, updated_at = datetime(\'now\') WHERE id = ?',
  ).bind(displayName, userId).run()

  const user = await c.env.DB.prepare(
    'SELECT id, email, display_name, avatar_url FROM users WHERE id = ?',
  ).bind(userId).first<{ id: string; email: string; display_name: string | null; avatar_url: string | null }>()

  return c.json({
    user: {
      id: user!.id,
      email: user!.email,
      displayName: user!.display_name,
      avatarUrl: user!.avatar_url,
    },
  })
})

// ─── 11. POST /avatar — 上传头像 ───

const ALLOWED_TYPES: Record<string, string> = {
  'image/jpeg': 'jpg',
  'image/png': 'png',
  'image/webp': 'webp',
}
const MAX_AVATAR_SIZE = 2 * 1024 * 1024 // 2MB

authRoutes.post('/avatar', authMiddleware, async (c) => {
  const userId = c.get('userId')

  const formData = await c.req.formData()
  const file = formData.get('avatar')
  if (!file || !(file instanceof File)) {
    return c.json({ error: 'No avatar file provided' }, 400)
  }

  if (!ALLOWED_TYPES[file.type]) {
    return c.json({ error: 'Only jpg, png, webp allowed' }, 400)
  }

  if (file.size > MAX_AVATAR_SIZE) {
    return c.json({ error: 'File too large, max 2MB' }, 400)
  }

  const key = `avatars/${userId}`
  const arrayBuffer = await file.arrayBuffer()

  await c.env.AVATARS.put(key, arrayBuffer, {
    httpMetadata: { contentType: file.type },
  })

  // Build avatar URL using the public endpoint
  const origin = new URL(c.req.url).origin
  const avatarUrl = `${origin}/auth/avatar/${userId}`

  await c.env.DB.prepare(
    'UPDATE users SET avatar_url = ?, updated_at = datetime(\'now\') WHERE id = ?',
  ).bind(avatarUrl, userId).run()

  return c.json({ avatarUrl })
})

// ─── 12. GET /avatar/:userId — 公开头像端点 ───

authRoutes.get('/avatar/:userId', async (c) => {
  const userId = c.req.param('userId')
  const key = `avatars/${userId}`

  const object = await c.env.AVATARS.get(key)
  if (!object) {
    return c.json({ error: 'Avatar not found' }, 404)
  }

  const headers = new Headers()
  headers.set('Content-Type', object.httpMetadata?.contentType || 'image/jpeg')
  headers.set('Cache-Control', 'public, max-age=86400')

  return new Response(object.body, { headers })
})

import { test, expect } from '@playwright/test';

type WarehouseStorage = {
  items: Record<string, number>;
  legendaryPity: number;
  totalCollected: number;
};

type FarmStorage = {
  plots: Array<{ state: string }>;
  collection: Array<{ varietyId: string }>;
};

async function dismissGuideIfPresent(page: import('@playwright/test').Page) {
  const getStarted = page.locator('button', { hasText: 'Get Started' });
  if (await getStarted.isVisible({ timeout: 2000 }).catch(() => false)) {
    await getStarted.click();
    await getStarted.waitFor({ state: 'hidden', timeout: 3000 }).catch(() => {});
  }
}

async function activateDebugMode(page: import('@playwright/test').Page) {
  await page.goto('/');
  await dismissGuideIfPresent(page);

  const settingsButton = page.getByRole('button', { name: /settings|设置/i });
  await settingsButton.click();

  const versionBadge = page.locator('.settings-scrollbar span').filter({ hasText: /^v\d+\.\d+\.\d+$/ });
  await expect(versionBadge).toBeVisible();

  for (let i = 0; i < 7; i += 1) {
    await versionBadge.click();
  }

  await expect(page.getByText('🧪 Debug Toolbar')).toBeVisible();
}

async function openDebugPanel(page: import('@playwright/test').Page) {
  const title = page.getByText('🧪 Debug Toolbar');
  const resetAllButton = page.getByRole('button', { name: '🔄 重置所有数据' });

  if (!(await resetAllButton.isVisible().catch(() => false))) {
    await title.click();
  }

  await expect(resetAllButton).toBeVisible();
}

async function readWarehouseStorage(page: import('@playwright/test').Page) {
  return page.evaluate(() => {
    const raw = localStorage.getItem('watermelon-warehouse');
    return raw ? JSON.parse(raw) as WarehouseStorage : null;
  });
}

async function readFarmStorage(page: import('@playwright/test').Page) {
  return page.evaluate(() => {
    const raw = localStorage.getItem('watermelon-farm');
    return raw ? JSON.parse(raw) as FarmStorage : null;
  });
}

test.describe('Debug toolbar E2E', () => {
  test('warehouse actions keep working (add/reset)', async ({ page }) => {
    await activateDebugMode(page);
    await openDebugPanel(page);

    const warehouseSection = page.locator('section').filter({ hasText: '瓜棚道具' });
    const seedRow = warehouseSection.locator('div').filter({ hasText: 'seed 🌱' }).first();

    await seedRow.getByRole('button', { name: '+10' }).click();

    await expect.poll(async () => (await readWarehouseStorage(page))?.items.seed ?? -1).toBe(10);
    await expect.poll(async () => (await readWarehouseStorage(page))?.totalCollected ?? -1).toBe(10);

    await warehouseSection.getByRole('button', { name: '清空瓜棚' }).click();

    await expect.poll(async () => {
      const warehouse = await readWarehouseStorage(page);
      if (!warehouse) return -1;
      return Object.values(warehouse.items).reduce((sum, value) => sum + value, 0);
    }).toBe(0);
    await expect.poll(async () => (await readWarehouseStorage(page))?.totalCollected ?? -1).toBe(0);
    await expect.poll(async () => (await readWarehouseStorage(page))?.legendaryPity ?? -1).toBe(0);
  });

  test('farm actions keep working (+varieties/reset)', async ({ page }) => {
    await activateDebugMode(page);
    await openDebugPanel(page);

    const farmSection = page.locator('section').filter({ hasText: '农场' });

    await farmSection.getByRole('button', { name: '🌱 +3品种' }).click();
    await expect.poll(async () => (await readFarmStorage(page))?.collection.length ?? -1).toBe(3);

    await farmSection.getByRole('button', { name: '🗑️ 重置农场' }).click();
    await expect.poll(async () => (await readFarmStorage(page))?.collection.length ?? -1).toBe(0);
    await expect.poll(async () => {
      const farm = await readFarmStorage(page);
      return farm ? farm.plots.every((plot) => plot.state === 'empty') : false;
    }).toBe(true);
  });

  test('time multiplier actions keep working (active state switches)', async ({ page }) => {
    await activateDebugMode(page);
    await openDebugPanel(page);

    const multiplierSection = page.locator('section').filter({ hasText: '时间倍率' });
    const oneXButton = multiplierSection.getByRole('button', { name: '1x' });
    const tenXButton = multiplierSection.getByRole('button', { name: '10x' });

    const tenXBgBefore = await tenXButton.evaluate((el) => getComputedStyle(el).backgroundColor);
    const oneXBgBefore = await oneXButton.evaluate((el) => getComputedStyle(el).backgroundColor);

    await tenXButton.click();

    await expect.poll(async () => tenXButton.evaluate((el) => getComputedStyle(el).backgroundColor)).not.toBe(tenXBgBefore);
    await expect.poll(async () => oneXButton.evaluate((el) => getComputedStyle(el).backgroundColor)).not.toBe(oneXBgBefore);
  });

  test('reset all data clears localStorage and triggers a real page reload', async ({ page }) => {
    await page.addInitScript(() => {
      (window as any).__e2eNavigationType = performance.getEntriesByType('navigation')[0]?.type ?? 'unknown';
      (window as any).__e2eStorageLengthAtInit = localStorage.length;
      (window as any).__e2eStorageKeysAtInit = Object.keys(localStorage);
    });

    await activateDebugMode(page);
    await openDebugPanel(page);

    await page.evaluate(() => {
      localStorage.setItem('e2e-debug-toolbar-test', JSON.stringify({ foo: 'bar' }));
      localStorage.setItem('e2e-debug-toolbar-test-2', '1');
    });

    await expect.poll(async () => page.evaluate(() => localStorage.length)).toBeGreaterThan(0);

    await Promise.all([
      page.waitForFunction(() => (window as any).__e2eNavigationType === 'reload'),
      page.getByRole('button', { name: '🔄 重置所有数据' }).click(),
    ]);

    await page.waitForLoadState('domcontentloaded');

    await expect.poll(async () => page.evaluate(() => (window as any).__e2eNavigationType)).toBe('reload');
    await expect.poll(async () => page.evaluate(() => (window as any).__e2eStorageLengthAtInit)).toBe(0);
    await expect.poll(async () => page.evaluate(() => (window as any).__e2eStorageKeysAtInit.length)).toBe(0);
  });
});

import { test, expect } from '@playwright/test';
import { readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

/**
 * E2E: 瓜田布局改版 v0.23.0 — 全部验收标准覆盖
 *
 * AC1:  3×3 CSS Grid + perspective rotateX 伪 3D
 * AC2:  7 块地始终显示，4 块已开发 + 3 块锁定
 * AC3:  LockedPlotCard 组件存在且显示锁定状态
 * AC4:  farmUnlockHint i18n 8 种语言都有
 * AC5:  圆角矩形地块，diamondClip 完全移除
 * AC6:  地块比例 3:4（宽:高）
 * AC7:  transformStyle 为 flat
 * AC8:  手机端（375px 宽度）一屏显示 7 块地不溢出
 * AC9:  种植弹窗 / 揭晓动画 / 收获动画正常
 * AC10: package.json version = 0.23.0
 * AC11: DEVLOG / CHANGELOG / PRODUCT / README 都有 v0.23.0 条目
 * AC12: build 通过（CI 层面验证，此处跳过）
 * AC13: push 到 origin/main（CI 层面验证，此处跳过）
 */

// Helper: navigate to farm tab
async function goToFarm(page: import('@playwright/test').Page) {
  await page.goto('/');
  // Dismiss onboarding if present
  const getStarted = page.locator('button', { hasText: 'Get Started' });
  if (await getStarted.isVisible({ timeout: 2000 }).catch(() => false)) {
    await getStarted.click();
    await getStarted.waitFor({ state: 'hidden', timeout: 3000 }).catch(() => {});
  }
  // Click farm tab (🌱)
  const farmTab = page.locator('button', { hasText: '🌱' });
  await farmTab.click();
  await page.waitForSelector('.farm-grid-perspective', { timeout: 5000 });
}

// ─── AC1: 3×3 CSS Grid + perspective rotateX ───
test('AC1: farm uses 3×3 CSS Grid with perspective rotateX', async ({ page }) => {
  await goToFarm(page);

  const grid = page.locator('.farm-grid-perspective');
  await expect(grid).toBeVisible();

  // Verify grid-cols-3
  const gridStyle = await grid.evaluate((el) => {
    const cs = getComputedStyle(el);
    return {
      display: cs.display,
      gridTemplateColumns: cs.gridTemplateColumns,
      transform: cs.transform,
    };
  });
  expect(gridStyle.display).toBe('grid');
  // 3 columns → gridTemplateColumns should have 3 values
  const colCount = gridStyle.gridTemplateColumns.split(/\s+/).length;
  expect(colCount).toBe(3);
  // transform should contain a matrix (from perspective + rotateX)
  expect(gridStyle.transform).not.toBe('none');
});

// ─── AC2: 7 块地始终显示 ───
test('AC2: 7 plot slots rendered (4 active + 3 locked)', async ({ page }) => {
  await goToFarm(page);

  const grid = page.locator('.farm-grid-perspective');
  const slots = grid.locator('> div');
  await expect(slots).toHaveCount(7);

  // Count locked plots (contain 🔒)
  const lockedSlots = grid.locator('> div').filter({ hasText: '🔒' });
  const lockedCount = await lockedSlots.count();
  expect(lockedCount).toBe(3);
});

// ─── AC3: LockedPlotCard 显示锁定状态 ───
test('AC3: LockedPlotCard shows lock icon and unlock hint text', async ({ page }) => {
  await goToFarm(page);

  const lockedCards = page.locator('.farm-grid-perspective > div').filter({ hasText: '🔒' });
  const count = await lockedCards.count();
  expect(count).toBeGreaterThan(0);

