/**
 * useWarehouse — 瓜棚数据管理 hook
 *
 * 管理收获物存储、合成操作、保底计数器。
 * 数据持久化到 localStorage。
 */
import { useCallback, useEffect, useRef } from 'react';
import { useLocalStorage } from './useLocalStorage';
import type { GrowthStage, Warehouse, SynthesisRecipe } from '../types';
import { DEFAULT_WAREHOUSE, SYNTHESIS_RECIPES } from '../types';

const WAREHOUSE_KEY = 'watermelon-warehouse';

function migrateWarehouse(raw: unknown): Warehouse {
  if (!raw || typeof raw !== 'object') return DEFAULT_WAREHOUSE;
  const w = raw as Record<string, unknown>;
  const result = { ...DEFAULT_WAREHOUSE };
  if (w.items && typeof w.items === 'object') {
    const items = w.items as Record<string, number>;
    for (const key of Object.keys(result.items) as GrowthStage[]) {
      if (typeof items[key] === 'number') result.items[key] = items[key];
    }
  }
  if (typeof w.legendaryPity === 'number') result.legendaryPity = w.legendaryPity;
  if (typeof w.totalCollected === 'number') result.totalCollected = w.totalCollected;
  return result;
}

export function useWarehouse(onSync?: (warehouse: Warehouse) => void) {
  const [warehouse, setWarehouse] = useLocalStorage<Warehouse>(WAREHOUSE_KEY, DEFAULT_WAREHOUSE, migrateWarehouse);

  // Sync warehouse to cloud on changes (skip initial mount)
  const onSyncRef = useRef(onSync);
  onSyncRef.current = onSync;
  const mountedRef = useRef(false);
  useEffect(() => {
    if (!mountedRef.current) {
      mountedRef.current = true;
      return;
    }
    onSyncRef.current?.(warehouse);
  }, [warehouse]);

  /** 添加收获物到瓜棚 */
  const addItem = useCallback((stage: GrowthStage) => {
    setWarehouse((prev) => ({
      ...prev,
      items: { ...prev.items, [stage]: prev.items[stage] + 1 },
      totalCollected: prev.totalCollected + 1,
    }));
  }, [setWarehouse]);

  /** 更新保底计数器（≥90min 未出金西瓜时 +1，出了时重置） */
  const updatePity = useCallback((gotLegendary: boolean) => {
    setWarehouse((prev) => ({
      ...prev,
      legendaryPity: gotLegendary ? 0 : prev.legendaryPity + 1,
    }));
  }, [setWarehouse]);

  /** 执行合成（手动触发，无自动合成） */
  const synthesize = useCallback((recipe: SynthesisRecipe, count: number = 1): boolean => {
    const available = warehouse.items[recipe.from];
    const maxCount = Math.floor(available / recipe.cost);
    const actual = Math.min(count, maxCount);
    if (actual <= 0) return false;

    setWarehouse((prev) => ({
      ...prev,
      items: {
        ...prev.items,
        [recipe.from]: prev.items[recipe.from] - actual * recipe.cost,
        [recipe.to]: prev.items[recipe.to] + actual,
      },
    }));
    return true;
  }, [warehouse.items, setWarehouse]);

  /** 合成全部（某条配方，手动触发） */
  const synthesizeAll = useCallback((recipe: SynthesisRecipe): number => {
    const available = warehouse.items[recipe.from];
    const count = Math.floor(available / recipe.cost);
    if (count <= 0) return 0;
    synthesize(recipe, count);
    return count;
  }, [warehouse.items, synthesize]);

  /** 获取最高阶收获物 */
  const getHighestStage = useCallback((): GrowthStage | null => {
    const order: GrowthStage[] = ['legendary', 'ripe', 'green', 'bloom', 'sprout', 'seed'];
    for (const stage of order) {
      if (warehouse.items[stage] > 0) return stage;
    }
    return null;
  }, [warehouse.items]);

  /** 切瓜时消耗一个大西瓜/金西瓜 */
  const consumeMelon = useCallback((type: 'ripe' | 'legendary'): boolean => {
    if (warehouse.items[type] <= 0) return false;
    setWarehouse((prev) => ({
      ...prev,
      items: { ...prev.items, [type]: prev.items[type] - 1 },
    }));
    return true;
  }, [warehouse.items, setWarehouse]);

  /** 批量添加收获物（测试用） */
  const addItems = useCallback((stage: GrowthStage, count: number) => {
    if (count <= 0) return;
    setWarehouse((prev) => ({
      ...prev,
      items: { ...prev.items, [stage]: prev.items[stage] + count },
      totalCollected: prev.totalCollected + count,
    }));
  }, [setWarehouse]);

  /** 清空瓜棚（测试用） */
  const resetWarehouse = useCallback(() => {
    setWarehouse({ ...DEFAULT_WAREHOUSE });
  }, [setWarehouse]);

  return {
    warehouse,
    setWarehouse,
    addItem,
    addItems,
    updatePity,
    consumeMelon,
    synthesize,
    synthesizeAll,
    getHighestStage,
    resetWarehouse,
    recipes: SYNTHESIS_RECIPES,
  };
}

/**
 * useWeeklyShop — Weekly market storage and purchase workflow.
 *
 * Responsibilities:
 * - Persist weekly shop to localStorage
 * - Refresh items at Monday 00:00 UTC
 * - Handle purchase flow: spend -> grant -> reduce stock
 */
import { useCallback, useEffect } from 'react';
import { useLocalStorage } from './useLocalStorage';
import type { VarietyId } from '../types/farm';
import { VARIETY_DEFS } from '../types/farm';
import type {
  WeeklyItem,
  WeeklyItemType,
  WeeklyShop,
  WeeklyDecorationId,
} from '../types/market';
import {
  createWeeklyShop,
  shouldRefreshWeeklyShop,
} from '../utils/weeklyShop';

const WEEKLY_SHOP_KEY = 'watermelon-weekly-shop';
const AUTO_REFRESH_CHECK_INTERVAL_MS = 60 * 1000;

interface UseWeeklyShopOptions {
  spendCoins: (amount: number) => boolean;
  onGrantItem: (item: WeeklyItem) => void;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null;
}

function isWeeklyItemType(value: unknown): value is WeeklyItemType {
  return value === 'rare-gene-fragment'
    || value === 'legendary-seed'
    || value === 'limited-decoration';
}

function isVarietyId(value: unknown): value is VarietyId {
  return typeof value === 'string' && Object.prototype.hasOwnProperty.call(VARIETY_DEFS, value);
}

function isWeeklyDecorationId(value: unknown): value is WeeklyDecorationId {
  return value === 'star-lamp'
    || value === 'melon-scarecrow'
    || value === 'nebula-banner'
    || value === 'mini-windmill'
    || value === 'meteor-stone';
}

function normalizeNumber(value: unknown, fallback: number): number {
  return typeof value === 'number' && Number.isFinite(value) ? value : fallback;
}

function normalizeWeeklyItem(raw: unknown): WeeklyItem | null {
  if (!isRecord(raw)) return null;
  if (typeof raw.id !== 'string' || raw.id.length === 0) return null;
  if (!isWeeklyItemType(raw.type)) return null;
  if (typeof raw.name !== 'string') return null;

  const price = Math.max(0, Math.floor(normalizeNumber(raw.price, 0)));
  const stock = Math.max(0, Math.floor(normalizeNumber(raw.stock, 0)));
  if (price <= 0) return null;

  if (!isRecord(raw.data)) return null;

  if (raw.type === 'rare-gene-fragment') {
    if (!isVarietyId(raw.data.varietyId)) return null;
    if (raw.data.rarity !== 'epic' && raw.data.rarity !== 'legendary') return null;
    const emoji = typeof raw.data.emoji === 'string' ? raw.data.emoji : VARIETY_DEFS[raw.data.varietyId].emoji;
    return {
      id: raw.id,
      type: raw.type,
      name: raw.name,
      price,
      stock,
      data: {
        varietyId: raw.data.varietyId,
        rarity: raw.data.rarity,
        emoji,
      },
    };
  }

  if (raw.type === 'legendary-seed') {
    if (!isVarietyId(raw.data.varietyId)) return null;
    const emoji = typeof raw.data.emoji === 'string' ? raw.data.emoji : VARIETY_DEFS[raw.data.varietyId].emoji;
    return {
      id: raw.id,
      type: raw.type,
      name: raw.name,
      price,
      stock,
      data: {
        varietyId: raw.data.varietyId,
        emoji,
      },
    };
  }

  if (!isWeeklyDecorationId(raw.data.decorationId)) return null;
  const emoji = typeof raw.data.emoji === 'string' ? raw.data.emoji : '🏮';
  return {
    id: raw.id,
    type: raw.type,
    name: raw.name,
    price,
    stock,
    data: {
      decorationId: raw.data.decorationId,
      emoji,
    },
  };
}

function migrateWeeklyShop(raw: unknown): WeeklyShop {
  const nowTimestamp = Date.now();
  if (!isRecord(raw) || !Array.isArray(raw.items)) {
    return createWeeklyShop(nowTimestamp);
  }

  const items = raw.items
    .map((item) => normalizeWeeklyItem(item))
    .filter((item): item is WeeklyItem => item !== null);

  const refreshAt = typeof raw.refreshAt === 'string' ? raw.refreshAt : '';
  const lastRefreshAt = typeof raw.lastRefreshAt === 'string' ? raw.lastRefreshAt : '';
  const hasValidRefreshAt = Number.isFinite(Date.parse(refreshAt));
  const hasValidLastRefreshAt = Number.isFinite(Date.parse(lastRefreshAt));

  if (items.length === 0 || !hasValidRefreshAt || !hasValidLastRefreshAt) {
    return createWeeklyShop(nowTimestamp);
  }

  const candidate: WeeklyShop = {
    items,
    refreshAt,
    lastRefreshAt,
  };
  return shouldRefreshWeeklyShop(candidate, nowTimestamp)
    ? createWeeklyShop(nowTimestamp)
    : candidate;
}

export function useWeeklyShop(options: UseWeeklyShopOptions) {
  const { spendCoins, onGrantItem } = options;
  const [weeklyShop, setWeeklyShop] = useLocalStorage<WeeklyShop>(
    WEEKLY_SHOP_KEY,
    createWeeklyShop(Date.now()),
    migrateWeeklyShop,
  );

  const refreshWeeklyShopIfNeeded = useCallback(() => {
    const nowTimestamp = Date.now();
    setWeeklyShop((prev) => (
      shouldRefreshWeeklyShop(prev, nowTimestamp)
        ? createWeeklyShop(nowTimestamp)
        : prev
    ));
  }, [setWeeklyShop]);

  useEffect(() => {
    refreshWeeklyShopIfNeeded();
  }, [refreshWeeklyShopIfNeeded]);

  useEffect(() => {
    const timerId = window.setInterval(refreshWeeklyShopIfNeeded, AUTO_REFRESH_CHECK_INTERVAL_MS);
    return () => window.clearInterval(timerId);
  }, [refreshWeeklyShopIfNeeded]);

  const buyWeeklyItem = useCallback((itemId: string): boolean => {
    if (shouldRefreshWeeklyShop(weeklyShop, Date.now())) {
      refreshWeeklyShopIfNeeded();
      return false;
    }

    const item = weeklyShop.items.find((entry) => entry.id === itemId);
    if (!item || item.stock <= 0) return false;

    const spent = spendCoins(item.price);
    if (!spent) return false;

    onGrantItem(item);
    setWeeklyShop((prev) => ({
      ...prev,
      items: prev.items.map((entry) => (
        entry.id === itemId
          ? { ...entry, stock: Math.max(0, entry.stock - 1) }
          : entry
      )),
    }));
    return true;
  }, [weeklyShop, refreshWeeklyShopIfNeeded, spendCoins, onGrantItem, setWeeklyShop]);

  return {
    weeklyShop,
    buyWeeklyItem,
  };
}
